package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCode;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.Locale;
import java.util.Objects;

@Service
class MfaBackupCodeService {
    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_BYTES = 9;

    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    MfaBackupCodeService(UserRepository userRepository, BackupCodeRepository backupCodeRepository) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = new BCryptPasswordEncoder();
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(String username, String mfaSecret) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaEnabled(true);
        user.setMfaSecret(mfaSecret);
        backupCodeRepository.findByUserIdAndUsedFalse(user.getId()).forEach(backupCodeRepository::delete);
        userRepository.save(user);
        return generateBackupCodesForUser(user, DEFAULT_CODE_COUNT);
    }

    @Transactional
    public List<String> generateBackupCodesForUser(AppUser user, int count) {
        List<String> plaintextCodes = new ArrayList<>();
        List<BackupCode> entities = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            String plaintext = generateHumanReadableCode();
            String hash = passwordEncoder.encode(normalizeCode(plaintext));
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(hash);
            code.setUsed(false);
            code.setCreatedAt(Instant.now());
            entities.add(code);
            plaintextCodes.add(plaintext);
        }
        backupCodeRepository.saveAll(entities);
        return plaintextCodes;
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String backupCode) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        List<BackupCode> activeCodes = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        String normalized = normalizeCode(backupCode);
        for (BackupCode code : activeCodes) {
            if (passwordEncoder.matches(normalized, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    @Transactional(readOnly = true)
    public long remainingBackupCodes(String username) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        return backupCodeRepository.countByUserIdAndUsedFalse(user.getId());
    }

    private String generateHumanReadableCode() {
        byte[] bytes = new byte[CODE_BYTES];
        secureRandom.nextBytes(bytes);
        String raw = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase(Locale.ROOT);
        return formatCode(raw);
    }

    private String formatCode(String raw) {
        String compact = raw.replaceAll("[^A-Z0-9]", "");
        StringBuilder sb = new StringBuilder();
        int groupSize = 4;
        for (int i = 0; i < compact.length(); i++) {
            sb.append(compact.charAt(i));
            if ((i + 1) % groupSize == 0 && i + 1 < compact.length()) {
                sb.append('-');
            }
        }
        return sb.toString();
    }

    private String normalizeCode(String code) {
        return Objects.requireNonNull(code, "code").replace("-", "").replace(" ", "").trim().toUpperCase(Locale.ROOT);
    }
}

package com.example.mfa.web;

import com.example.mfa.service.MfaBackupCodeService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/mfa")
class MfaController {
    private final MfaBackupCodeService backupCodeService;

    MfaController(MfaBackupCodeService backupCodeService) {
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enableMfa(@RequestBody EnableMfaRequest request) {
        List<String> backupCodes = backupCodeService.enableMfaAndGenerateBackupCodes(request.username(), request.mfaSecret());
        return ResponseEntity.ok(new EnableMfaResponse(true, backupCodes));
    }

    @PostMapping("/backup-authenticate")
    public ResponseEntity<BackupAuthenticateResponse> authenticateWithBackupCode(@RequestBody BackupAuthenticateRequest request) {
        boolean success = backupCodeService.authenticateWithBackupCode(request.username(), request.backupCode());
        if (success) {
            return ResponseEntity.ok(new BackupAuthenticateResponse(true, "Authentication successful using backup code"));
        }
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                .body(new BackupAuthenticateResponse(false, "Invalid or used backup code"));
    }

    @GetMapping("/backup-codes/{username}/remaining")
    public ResponseEntity<RemainingBackupCodesResponse> remaining(@PathVariable String username) {
        long count = backupCodeService.remainingBackupCodes(username);
        return ResponseEntity.ok(new RemainingBackupCodesResponse(username, count));
    }

    public record EnableMfaRequest(String username, String mfaSecret) {}
    public record EnableMfaResponse(boolean mfaEnabled, List<String> backupCodes) {}
    public record BackupAuthenticateRequest(String username, String backupCode) {}
    public record BackupAuthenticateResponse(boolean authenticated, String message) {}
    public record RemainingBackupCodesResponse(String username, long remainingBackupCodes) {}
}

